/* html2canvas placeholder — replace with the real vendored build.
 * Download from: https://html2canvas.hertzen.com/
 * or: npm pack html2canvas and copy dist/html2canvas.min.js here.
 *
 * This file must be present for the extension to load without errors.
 * The actual implementation is not included in this scaffold to keep
 * the repository lightweight.
 */
if (typeof html2canvas === 'undefined') {
  console.warn('[ui-annotator] html2canvas is not loaded. Replace lib/html2canvas.min.js with the real build.');
  // Provide a stub so content.js does not throw on load
  window.html2canvas = () => Promise.reject(new Error('html2canvas not loaded — see lib/html2canvas.min.js'));
}
